import React from 'react';

const getSeverityStyles = (severity) => {
  switch (severity) {
    case 'Severe': return 'bg-red-600 text-white';
    case 'High': return 'bg-orange-500 text-white';
    case 'Medium': return 'bg-yellow-400 text-black';
    case 'Low': return 'bg-green-500 text-white';
    default: return 'bg-gray-200 text-black';
  }
};

const LogTable = ({ logs }) => {
  if (!logs || logs.length === 0) {
    return <div className="p-8 text-center text-gray-500">No logs found matching criteria.</div>;
  }

  return (
    <div className="bg-white shadow-lg rounded-lg overflow-hidden border border-gray-200">
      <table className="min-w-full leading-normal">
        <thead>
          <tr className="bg-gray-100 border-b border-gray-200 text-left text-xs font-bold text-gray-600 uppercase tracking-wider">
            <th className="px-6 py-4">Timestamp</th>
            <th className="px-6 py-4">Source IP</th>
            <th className="px-6 py-4">Host</th>
            <th className="px-6 py-4">Message</th>
            <th className="px-6 py-4">Anomaly Score</th>
            <th className="px-6 py-4">Severity</th>
          </tr>
        </thead>
        <tbody>
          {logs.map((log, idx) => (
            <tr key={idx} className="border-b border-gray-100 hover:bg-blue-50 transition-colors">
              <td className="px-6 py-4 text-xs whitespace-nowrap text-gray-600">
                {new Date(log.timestamp).toLocaleString()}
              </td>
              <td className="px-6 py-4 text-sm font-mono text-blue-700">
                {log.source_ip || '---'}
              </td>
              <td className="px-6 py-4 text-sm font-medium text-gray-800">
                {log.host}
              </td>
              <td className="px-6 py-4 text-sm text-gray-700 break-words max-w-lg">
                {log.message}
              </td>
              <td className="px-6 py-4 text-sm">
                <span className={`font-bold ${log.anomaly_score < -0.7 ? 'text-red-500' : 'text-gray-400'}`}>
                  {log.anomaly_score.toFixed(3)}
                </span>
              </td>
              <td className="px-6 py-4 text-xs">
                <span className={`px-3 py-1 rounded-full font-bold uppercase ${getSeverityStyles(log.severity)}`}>
                  {log.severity}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default LogTable;
